// Validate and map all unprocessed rows from the intake sheet
// Returns two arrays: valid rows to upsert, and invalid rows to flag

const allRows = $input.all();
const patientCount = $('Get Patient Count for Code').first().json.total || 0;
const tz = $env.TIMEZONE || 'Asia/Kolkata';
const now = new Date();
const todayStr = now.toLocaleDateString('en-CA', { timeZone: tz }); // YYYY-MM-DD

// Filter: only rows where id column is empty (not yet synced)
// Also skip completely empty rows
const unprocessed = allRows.filter(item => {
  const r = item.json;
  const idVal = String(r.id || '').trim();
  if (idVal !== '') return false; // already synced (or marked INVALID/DUPLICATE)
  // Skip truly empty rows (all key fields blank)
  const hasAnyData = ['hospital_name','doctor_name','patient_name','phone_number'].some(f => String(r[f] || '').trim() !== '');
  return hasAnyData;
});

if (unprocessed.length === 0) {
  return [{ json: { _noNewRows: true, reason: 'No unprocessed rows in today\'s sheet', checkedAt: now.toISOString() } }];
}

// Track phones seen in this batch for duplicate detection
const seenPhones = {};
const output = [];
let codeOffset = patientCount;

for (const item of unprocessed) {
  const r = item.json;
  const errors = [];
  const warnings = [];

  // ── Required field checks ─────────────────────────────────────────────────
  if (!r.patient_name || String(r.patient_name).trim().length < 2) {
    errors.push('patient_name is required (min 2 characters)');
  }
  if (!r.hospital_name || String(r.hospital_name).trim() === '') {
    errors.push('hospital_name is required');
  }
  if (!r.doctor_name || String(r.doctor_name).trim() === '') {
    errors.push('doctor_name is required');
  }
  if (!r.visit_date || String(r.visit_date).trim() === '') {
    errors.push('visit_date is required');
  }
  if (!r.follow_up_required || String(r.follow_up_required).trim() === '') {
    errors.push('follow_up_required is required (Yes or No)');
  }

  // ── Phone validation ──────────────────────────────────────────────────────
  const rawPhone = String(r.phone_number || '').replace(/[\s\-().+]/g, '');
  let normPhone = null;

  if (!rawPhone) {
    errors.push('phone_number is required');
  } else if (!/^[0-9]{10}$/.test(rawPhone)) {
    errors.push(`phone_number "${r.phone_number}" must be exactly 10 digits (no country code, no spaces)`);
  } else {
    normPhone = '+91' + rawPhone; // prepend India country code — adjust per clinic country
  }

  // ── Duplicate phone check within current batch ───────────────────────────
  if (normPhone) {
    if (seenPhones[normPhone] !== undefined) {
      output.push({
        json: {
          _action: 'error',
          _errorCode: 'DUPLICATE',
          _raw: r,
          phone_number: r.phone_number,
          _errors: [`Duplicate phone_number in today's sheet. First occurrence already queued for sync.`]
        }
      });
      continue; // skip to next row
    }
    seenPhones[normPhone] = true;
  }

  // ── Date parsing helper ───────────────────────────────────────────────────
  function parseDate(val) {
    if (!val || String(val).trim() === '') return null;
    const s = String(val).trim();
    // Google Sheets may return DD/MM/YYYY or YYYY-MM-DD or a serial number
    let d;
    if (/^\d{2}\/\d{2}\/\d{4}$/.test(s)) {
      const [dd, mm, yyyy] = s.split('/');
      d = new Date(`${yyyy}-${mm}-${dd}`);
    } else if (/^\d{4}-\d{2}-\d{2}$/.test(s)) {
      d = new Date(s);
    } else {
      d = new Date(s); // fallback
    }
    if (isNaN(d.getTime())) return null;
    return d.toLocaleDateString('en-CA'); // → YYYY-MM-DD
  }

  const visitDateStr = parseDate(r.visit_date);
  const followUpDateStr = parseDate(r.follow_up_date);
  const dobStr = parseDate(r.dob);

  if (r.visit_date && !visitDateStr) {
    errors.push(`visit_date "${r.visit_date}" is not a valid date`);
  } else if (visitDateStr && visitDateStr > todayStr) {
    errors.push(`visit_date "${visitDateStr}" cannot be in the future`);
  }

  if (dobStr && dobStr >= todayStr) {
    errors.push(`dob "${dobStr}" must be in the past`);
  }

  // ── follow_up_required conditional logic ─────────────────────────────────
  const fuRequired = String(r.follow_up_required || '').trim();

  if (fuRequired === 'Yes') {
    if (!followUpDateStr) {
      errors.push('follow_up_date is required when follow_up_required = Yes');
    } else {
      if (visitDateStr && followUpDateStr <= visitDateStr) {
        errors.push(`follow_up_date (${followUpDateStr}) must be strictly after visit_date (${visitDateStr})`);
      }
    }
  } else if (fuRequired === 'No') {
    if (followUpDateStr) {
      warnings.push(`follow_up_date is set but follow_up_required = No — follow_up_date will be ignored`);
    }
  }

  // ── sex validation ────────────────────────────────────────────────────────
  const sex = String(r.sex || '').trim();
  if (sex && !['Male','Female','Other'].includes(sex)) {
    warnings.push(`sex "${sex}" is not a recognised value — will be ignored`);
  }

  // ── If errors found, queue as error ──────────────────────────────────────
  if (errors.length > 0) {
    output.push({
      json: {
        _action: 'error',
        _errorCode: 'INVALID',
        _raw: r,
        phone_number: rawPhone,
        _errors: errors,
        _warnings: warnings
      }
    });
    continue;
  }

  // ── Generate PAT-XXXX code ────────────────────────────────────────────────
  codeOffset++;
  const patientCode = 'PAT-' + String(codeOffset).padStart(4, '0');
  const nowISO = now.toISOString();

  // ── Map intake fields → Supabase patients schema ─────────────────────────
  output.push({
    json: {
      _action: 'upsert',
      _patientCode: patientCode,
      _normPhone: normPhone,
      _warnings: warnings,
      // Supabase patients columns
      patient_code: patientCode,
      name: String(r.patient_name).trim(),
      phone: normPhone,
      clinic_name: String(r.hospital_name).trim(),
      doctor_name: String(r.doctor_name).trim(),
      dob: dobStr || null,
      sex: ['Male','Female','Other'].includes(sex) ? sex : null,
      visit_date: visitDateStr || null,
      follow_up_required: fuRequired === 'Yes' ? 'Yes' : 'No',
      follow_up_date: fuRequired === 'Yes' ? followUpDateStr : null,
      status: 'pending',
      message_count: 0,
      response_status: 'none',
      health_check_sent: false,
      reactivation_sent: false,
      intake_sheet_id: $('Get Today\'s Sheet ID').first().json.spreadsheet_id,
      created_at: nowISO,
      updated_at: nowISO
    }
  });
}

if (output.length === 0) {
  return [{ json: { _noNewRows: true, reason: 'All rows were empty or already processed', checkedAt: now.toISOString() } }];
}

return output;
